class Calculator:
    def __init__(self, value=0):
        self.value = value

    def add(self, num):
        self.value += num
        return self

    def subtract(self, num):
        self.value -= num
        return self

    def get_value(self):
        return self.value

calc = Calculator(10)
result = calc.add(5).subtract(3).get_value()
print(result)

class Employee:
    company_name = "Tech Corp"

    def __init__(self, name, salary):
        self.name = name
        self.salary = salary

    @staticmethod
    def is_valid_salary(salary):
        return salary > 0

    @classmethod
    def from_string(cls, emp_str):
        name, salary = emp_str.split("-")
        return cls(name, int(salary))

    def display(self):
        return f"{self.name}: ${self.salary}"

emp1 = Employee("Alice", 50000)
emp2 = Employee.from_string("Bob-60000")

print(Employee.is_valid_salary(50000))
print(Employee.company_name)
print(emp1.display())
print(emp2.display())
